parameters.jsCode:
const {
  employees = [],
  matrices = [],
  learning_assets = [],
  self_assessments = [],
  data_quality_issues = [],
  employee_id,
  config = {}
} = $json;

const employee = employees.find(e => e.employee_id === employee_id) || null;
if (!employee) {
  return [{
    json: {
      employee: null,
      self_assessment: null,
      role_matrix: null,
      learning_assets_pool: [],
      employee_data_quality_issues: [{
        severity: 'error',
        entity_type: 'employee',
        entity_id: employee_id,
        issue_code: 'employee_not_found',
        message: `Сотрудник ${employee_id} не найден`
      }]
    }
  }];
}

const role_matrix = matrices.find(m => m.role === employee.role) || null;
const self_assessment = self_assessments.find(s => s.employee_id === employee.employee_id) || null;

const learning_assets_pool = learning_assets.filter(asset => {
  if (!asset.recommended_for_roles || asset.recommended_for_roles.length === 0) return true;
  return asset.recommended_for_roles.includes(employee.role);
});

const employee_data_quality_issues = data_quality_issues.filter(issue =>
  !issue.entity_id ||
  issue.entity_id === employee.employee_id ||
  issue.entity_id === employee.role
);

return [{
  json: {
    employee,
    self_assessment,
    role_matrix,
    learning_assets_pool,
    employee_data_quality_issues,
    config
  }
}];

const competency_items = $json.competency_items || [];

function scoreItem(item) {
  const comp = item.competency || {};
  const self = item.self_assessment_item || {};
  const jira = item.jira_evidence || [];

  const priorityWeight = Number(comp.priority_weight || 0.5);
  const selfLevel = Number(self.selected_level || 0);
  const targetLevel = Number(item.target_level || 3);
  const gap = Math.max(0, targetLevel - selfLevel);

  const hasComment = self.comment && self.comment.trim().length > 20 ? 1 : 0;
  const jiraSignal = Math.min(jira.length, 3) / 3;

  let typeFactor = 1;
  if (comp.type === 'soft') typeFactor = 0.85;
  if (comp.type === 'management') typeFactor = 0.8;

  const score =
    priorityWeight * 0.35 +
    gap * 0.25 +
    hasComment * 0.15 +
    jiraSignal * 0.15 +
    typeFactor * 0.10;

  return Number(score.toFixed(4));
}

const scored = competency_items.map(item => ({
  ...item,
  candidate_score: scoreItem(item)
}));

return [{
  json: {
    ...$json,
    competency_items_scored: scored
  }
}];

const itemsScored = $json.competency_items_scored || [];
const maxCompetencies = $json.config?.max_competencies_for_llm || 12;

const sorted = [...itemsScored].sort((a, b) => b.candidate_score - a.candidate_score);
const shortlisted = sorted.slice(0, maxCompetencies);

return [{
  json: {
    ...$json,
    shortlisted_competencies: shortlisted
  }
}];

// Получаем данные из входного массива
const inputData = items[0]?.json || {};

// Извлекаем необходимые данные
const employee = inputData.employee || {};
const config = inputData.config || {};

// Определяем, какой массив компетенций использовать (приоритет: shortlisted > scored > items)
let competencySource = inputData.shortlisted_competencies || 
                       inputData.competency_items_scored || 
                       inputData.competency_items || [];

// Если нет компетенций в специализированных массивах, берем из role_matrix
if (competencySource.length === 0 && inputData.role_matrix?.competencies) {
  competencySource = inputData.role_matrix.competencies.map(comp => ({
    competency: comp,
    self_assessment_item: {
      competency_id: comp.competency_id,
      selected_level: null,
      comment: ''
    },
    jira_evidence: [],
    target_level: 0,
    candidate_score: null
  }));
}

// Функция для удаления дубликатов по competency_id
function uniqueByCompetencyId(items) {
  const seen = new Map();
  for (const item of items) {
    const competencyId = item.competency?.competency_id;
    if (competencyId && !seen.has(competencyId)) {
      seen.set(competencyId, item);
    }
  }
  return Array.from(seen.values());
}

// Удаляем дубликаты компетенций
const uniqueCompetencyItems = uniqueByCompetencyId(competencySource);

// Создаем массив объектов для батчевой обработки
const result = [];

for (const item of uniqueCompetencyItems) {
  const competency = item.competency || {};
  const selfAssessmentItem = item.self_assessment_item || {};
  const targetLevel = item.target_level || 0;

  // Определяем selected_level: сначала из self_assessment_item, потом из item
  let selectedLevel = selfAssessmentItem.selected_level;
  if (selectedLevel === undefined || selectedLevel === null) {
    selectedLevel = item.selected_level;
  }

  // Формируем объект для одной компетенции
  result.push({
    employee: {
      employee_id: employee.employee_id || '',
      full_name: employee.full_name || '',
      role: employee.role || '',
      position: employee.position || '',
      team: employee.team || '',
      grade: employee.grade || ''
    },
    competency: {
      competency_id: competency.competency_id || '',
      name: competency.name || '',
      type: competency.type || '',
      category: competency.category || '',
      description: competency.description || '',
      levels: competency.levels || [],
      priority_weight: competency.priority_weight || config.default_competency_priority_weight || 0.5
    },
    target_level: targetLevel,
    self_assessment_item: {
      selected_level: (selectedLevel !== undefined && selectedLevel !== null) ? selectedLevel : null,
      comment: selfAssessmentItem.comment || ''
    },
    // Дополнительные поля, которые могут пригодиться
    candidate_score: item.candidate_score || null,
    jira_evidence: item.jira_evidence || [],
    // Метаданные для отслеживания
    _metadata: {
      competency_index: result.length + 1,
      total_competencies: uniqueCompetencyItems.length,
      source: item.candidate_score !== undefined ? 'scored' : 
              (item.target_level ? 'items' : 'matrix'),
      processing_timestamp: new Date().toISOString()
    }
  });
}

// Если нет компетенций, возвращаем информацию об ошибке
if (result.length === 0) {
  return [{
    json: {
      error: "Нет компетенций для обработки",
      employee_id: employee.employee_id || 'unknown',
      available_arrays: {
        has_shortlisted: !!inputData.shortlisted_competencies,
        has_scored: !!inputData.competency_items_scored,
        has_items: !!inputData.competency_items,
        has_role_matrix: !!inputData.role_matrix?.competencies
      },
      message: "Проверьте наличие компетенций в данных"
    }
  }];
}

// Возвращаем массив объектов для Split In Batches
// Каждый объект станет отдельным item в батче
return result;

