=Проанализируй компетенцию и верни JSON по схеме:
{ "competency_id": "string",  "self_level": 0,  "estimated_level": 0,  "confidence": "low|medium|high",  "assessment": "string",  "evidence_for": ["string"],  "evidence_missing": ["string"],  "risk_flags": ["string"],  "priority": "low|medium|high",  "development_focus": "string"}

Данные: {{ JSON.stringify($json.payload) }}

parameters.jsCode:
// Сохраняем все данные во временное поле
const inputData = $input.item.json;

return [{
  json: {
  original_data: inputData,
  // Если нужно, можно сохранить отдельные поля
  employee: inputData.employee,
  competency: inputData.competency,
  target_level: inputData.target_level,
  candidate_score: inputData.candidate_score,
  jira_evidence: inputData.jira_evidence,
  self_assessment_item: inputData.self_assessment_item,
    _metadata: inputData._metadata,

  }
}];

const originalData = items[0]?.json?.original_data || {};
const openAiResponse = items[0]?.json?.text || items[0]?.json?.message || {};

// Восстанавливаем полную структуру
return [{
  json: {
    ...originalData,           // Все исходные данные
    openai_response: openAiResponse,  // Ответ OpenAI
    // Можно добавить метаданные
    processed_at: new Date().toISOString(),
    ai_model: 'openai'
  }
}];

// Получаем данные
const data = items[0]?.json || {};

// Парсим text если он есть и это строка
let aiData = {};
if (data.text) {
  try {
    aiData = typeof data.text === 'string' ? JSON.parse(data.text) : data.text;
  } catch (e) {
    console.error('Ошибка парсинга:', e);
  }
}

// Объединяем данные
const result = {
  ...data,
  // Добавляем распарсенные данные на верхний уровень
  self_level: aiData.self_level,
  estimated_level: aiData.estimated_level,
  confidence: aiData.confidence,
  assessment: aiData.assessment,
  priority: aiData.priority,
  development_focus: aiData.development_focus,
  evidence_for: aiData.evidence_for || [],
  evidence_missing: aiData.evidence_missing || [],
  risk_flags: aiData.risk_flags || [],
  // Сохраняем оригинальный aiData для отладки
  _ai_parsed: aiData
};

return [{
  json: result
}];

function safeParse(content) {
  if (typeof content === 'object' && content !== null) return content;
  if (typeof content === 'string') {
    try {
      return JSON.parse(content);
    } catch (e) {
      return null;
    }
  }
  return null;
}

function normalizeEnum(value, allowed, fallback) {
  return allowed.includes(value) ? value : fallback;
}

// Пытаемся получить контент из разных возможных полей
let raw = null;

// Вариант 1: из choices (как в стандартном ответе OpenAI)
if ($json.choices?.[0]?.message?.content) {
  raw = $json.choices[0].message.content;
}
// Вариант 2: из поля text (как в вашем случае)
else if ($json.text) {
  raw = $json.text;
}
// Вариант 3: из message.content
else if ($json.message?.content) {
  raw = $json.message.content;
}
// Вариант 4: из content
else if ($json.content) {
  raw = $json.content;
}
// Вариант 5: если сам $json уже содержит данные
else if ($json.competency_id || $json.estimated_level) {
  raw = $json;
}

// Парсим данные
const parsed = safeParse(raw);

if (!parsed) {
  return [{
    json: {
      valid: false,
      error: 'invalid_json_from_llm',
      raw_content: typeof raw === 'string' ? raw.substring(0, 200) : raw,
      competency_result: null
    }
  }];
}

// Извлекаем данные, поддерживая оба формата: прямой и вложенный
const competencyId = parsed.competency_id || $json.competency_id || '';
const selfLevel = parsed.self_level !== undefined ? parsed.self_level : $json.self_level;
const estimatedLevel = parsed.estimated_level !== undefined ? parsed.estimated_level : $json.estimated_level;

const result = {
  competency_id: competencyId,
  self_level: Number.isFinite(Number(selfLevel)) ? Number(selfLevel) : null,
  estimated_level: Number.isFinite(Number(estimatedLevel)) ? Number(estimatedLevel) : null,
  confidence: normalizeEnum(parsed.confidence || $json.confidence, ['low', 'medium', 'high'], 'low'),
  assessment: String(parsed.assessment || $json.assessment || ''),
  evidence_for: Array.isArray(parsed.evidence_for || $json.evidence_for) ? (parsed.evidence_for || $json.evidence_for) : [],
  evidence_missing: Array.isArray(parsed.evidence_missing || $json.evidence_missing) ? (parsed.evidence_missing || $json.evidence_missing) : [],
  risk_flags: Array.isArray(parsed.risk_flags || $json.risk_flags) ? (parsed.risk_flags || $json.risk_flags) : [],
  priority: normalizeEnum(parsed.priority || $json.priority, ['low', 'medium', 'high'], 'medium'),
  development_focus: String(parsed.development_focus || $json.development_focus || '')
};

// Проверяем валидность
const valid = !!(result.competency_id && result.estimated_level !== null);

return [{
  json: {
    valid: valid,
    error: valid ? null : 'missing_required_fields',
    competency_result: result,
    // Добавляем отладочную информацию
    _debug: {
      raw_type: typeof raw,
      parsed_success: !!parsed,
      available_fields: Object.keys(parsed || {}),
      competency_id_found: !!result.competency_id,
      estimated_level_found: result.estimated_level !== null
    }
  }
}];

const item = $input.first().json.payload || {};
const self = item.self_assessment_item || {};
const comp = item.competency || {};

return [{
  json: {
    valid: true,
    error: 'fallback_used',
    competency_result: {
      competency_id: comp.competency_id,
      self_level: self.selected_level ?? null,
      estimated_level: self.selected_level ?? 0,
      confidence: 'low',
      assessment: 'LLM-анализ недоступен, использована базовая интерпретация самооценки без качественного анализа.',
      evidence_for: [],
      evidence_missing: ['Недостаточно валидного LLM-анализа'],
      risk_flags: ['fallback_used'],
      priority: 'medium',
      development_focus: 'Требуется ручная проверка'
    }
  }
}];

const {
  employee,
  jira_summary = {},
  employee_data_quality_issues = []
} = $json;

const competency_results = $json.competency_results || [];

const payload = {
  employee: {
    employee_id: employee.employee_id,
    full_name: employee.full_name,
    role: employee.role,
    position: employee.position,
    team: employee.team,
    grade: employee.grade
  },
  jira_summary: {
    available: jira_summary.available ?? false,
    summary: jira_summary.summary || '',
    confidence: jira_summary.confidence || 'low',
    evidence_items: jira_summary.evidence_items || []
  },
  competency_results,
  data_quality_flags: employee_data_quality_issues.map(i => ({
    severity: i.severity,
    issue_code: i.issue_code,
    message: i.message
  }))
};

return [{
  json: {
    ...$json,
    employee_summary_payload: payload
  }
}];

function safeParse(content) {
  if (typeof content === 'object' && content !== null) return content;
  try {
    return JSON.parse(content);
  } catch (e) {
    return null;
  }
}

function normArray(v) {
  return Array.isArray(v) ? v.map(x => String(x)) : [];
}

const raw =
  $json.choices?.[0]?.message?.content ??
  $json.message?.content ??
  $json.content ??
  $json;

const parsed = safeParse(raw);

if (!parsed) {
  return [{
    json: {
      valid: false,
      error: 'invalid_json_from_llm',
      employee_summary: null
    }
  }];
}

const employee_summary = {
  overall_summary: String(parsed.overall_summary || ''),
  strengths: normArray(parsed.strengths),
  growth_areas: normArray(parsed.growth_areas),
  alignment: {
    overestimated: normArray(parsed.alignment?.overestimated),
    underestimated: normArray(parsed.alignment?.underestimated),
    aligned: normArray(parsed.alignment?.aligned)
  },
  top_priorities_next_6m: normArray(parsed.top_priorities_next_6m),
  confidence: ['low', 'medium', 'high'].includes(parsed.confidence) ? parsed.confidence : 'low'
};

return [{
  json: {
    valid: true,
    error: null,
    employee_summary
  }
}];

const competency_results = $json.competency_results || [];
const employee_summary = $json.employee_summary || {};
const jira_summary = $json.jira_summary || {};

const lowConfidenceCount = competency_results.filter(x => x.confidence === 'low').length;
const totalCount = competency_results.length || 1;

const analysis_quality = lowConfidenceCount / totalCount > 0.5 ? 'low' : 'medium';

const top_priority_competencies = competency_results
  .filter(x => x.priority === 'high' || x.priority === 'medium')
  .sort((a, b) => {
    const pr = { high: 3, medium: 2, low: 1 };
    return pr[b.priority] - pr[a.priority];
  })
  .slice(0, 8)
  .map(x => x.competency_id);

const flags = [];
if (!jira_summary.available) {
  flags.push('jira_unavailable');
}
if (analysis_quality === 'low') {
  flags.push('low_evidence_confidence');
}

return [{
  json: {
    competency_analysis: {
      competency_results,
      employee_summary,
      top_priority_competencies,
      analysis_quality,
      flags
    }
  }
}];

const {
  employee,
  role_matrix,
  learning_assets_pool = [],
  jira_summary = {},
  competency_analysis = {},
  config = {}
} = $json;

return [{
  json: {
    employee,
    role_matrix,
    learning_assets_pool,
    jira_summary,
    competency_analysis,
    config: {
      plan_duration_months: config.plan_duration_months || 6,
      quarters: config.quarters || 2,
      max_competencies_per_quarter: config.max_competencies_per_quarter || 4,
      max_assets_per_competency: config.max_assets_per_competency || 5
    }
  }
}];

const groups =
  $json.role_matrix?.compentecy_groups ||
  $json.role_matrix?.competency_groups ||
  [];

const competency_map = {};

for (const group of groups) {
  for (const c of (group.competencies || [])) {
    const competency_id = c.competency_id || c.id;
    if (!competency_id) continue;

    competency_map[competency_id] = {
      competency_id,
      name: c.competency_name || c.name || competency_id,
      type: c.type || group.type || 'hard',
      description: c.description || '',
      levels: c.levels || [],
      group_name: group.group_name || group.name || ''
    };
  }
}

return [{
  json: {
    ...$json,
    competency_map
  }
}];

const {
  learning_assets_pool = [],
  competency_analysis = {},
  competency_map = {},
  config = {}
} = $json;

const maxAssetsPerCompetency = config.max_assets_per_competency || 5;

const topPriorityIds =
  competency_analysis.top_priority_competencies?.length
    ? competency_analysis.top_priority_competencies
    : (competency_analysis.competency_results || [])
        .filter(x => x.priority === 'high')
        .map(x => x.competency_id);

const result = [];

for (const competency_id of topPriorityIds) {
  const compMeta = competency_map[competency_id];
  if (!compMeta) continue;

  const matched = learning_assets_pool
    .filter(asset => Array.isArray(asset.competencies) && asset.competencies.includes(competency_id))
    .slice(0, maxAssetsPerCompetency);

  result.push({
    competency_id,
    competency_name: compMeta.name,
    competency_type: compMeta.type,
    matched_assets: matched
  });
}

return [{
  json: {
    ...$json,
    learning_matches: result
  }
}];

const {
  competency_analysis = {},
  competency_map = {},
  learning_matches = []
} = $json;

const results = competency_analysis.competency_results || [];
const learningMap = new Map(
  learning_matches.map(x => [x.competency_id, x])
);

const planning_candidates = results
  .filter(r => competency_analysis.top_priority_competencies?.includes(r.competency_id))
  .map(r => {
    const meta = competency_map[r.competency_id] || {};
    const match = learningMap.get(r.competency_id);

    return {
      competency_id: r.competency_id,
      competency_name: meta.name || r.competency_id,
      competency_type: meta.type || 'hard',
      description: meta.description || '',
      levels: meta.levels || [],
      self_level: r.self_level,
      estimated_level: r.estimated_level,
      target_level: null,
      confidence: r.confidence,
      assessment: r.assessment,
      development_focus: r.development_focus,
      evidence_for: r.evidence_for || [],
      evidence_missing: r.evidence_missing || [],
      priority: r.priority,
      learning_assets: match?.matched_assets || []
    };
  });

return [{
  json: {
    ...$json,
    planning_candidates
  }
}];

const candidates = $json.planning_candidates || [];
const maxTotal = ($json.config?.max_competencies_per_quarter || 4) * 2;

function scoreCandidate(c) {
  const priorityScore = c.priority === 'high' ? 3 : c.priority === 'medium' ? 2 : 1;
  const confidencePenalty = c.confidence === 'low' ? -0.5 : 0;
  const typeBonus = c.competency_type === 'hard' || c.competency_type === 'technology' ? 0.3 : 0;
  const hasAssets = (c.learning_assets || []).length > 0 ? 0.2 : 0;
  return priorityScore + confidencePenalty + typeBonus + hasAssets;
}

const shortlisted = [...candidates]
  .sort((a, b) => scoreCandidate(b) - scoreCandidate(a))
  .slice(0, maxTotal);

return [{
  json: {
    ...$json,
    shortlisted_plan_candidates: shortlisted
  }
}];

const {
  employee,
  jira_summary = {},
  competency_analysis = {},
  shortlisted_plan_candidates = [],
  config = {}
} = $json;

const payload = {
  employee: {
    employee_id: employee.employee_id,
    full_name: employee.full_name,
    role: employee.role,
    position: employee.position,
    team: employee.team,
    grade: employee.grade
  },
  employee_summary: competency_analysis.employee_summary || {},
  jira_summary: {
    available: jira_summary.available ?? false,
    summary: jira_summary.summary || '',
    confidence: jira_summary.confidence || 'low'
  },
  constraints: {
    plan_duration_months: config.plan_duration_months || 6,
    quarters: config.quarters || 2,
    max_competencies_per_quarter: config.max_competencies_per_quarter || 4,
    max_total_competencies: (config.max_competencies_per_quarter || 4) * (config.quarters || 2)
  },
  planning_candidates: shortlisted_plan_candidates
};

return [{
  json: {
    ...$json,
    development_plan_payload: payload
  }
}];

parameters.text:
=Верни JSON по схеме:

{
  "development_plan": {
    "quarter_1": [
      {
        "competency_id": "string",
        "competency_name": "string",
        "reason": "string",
        "target_from": 0,
        "target_to": 0,
        "actions": [
          {
            "type": "course|program|practice|mentoring|reading|shadowing|project",
            "title": "string",
            "description": "string"
          }
        ],
        "success_criteria": ["string"],
        "manager_support": ["string"]
      }
    ],
    "quarter_2": [
      {
        "competency_id": "string",
        "competency_name": "string",
        "reason": "string",
        "target_from": 0,
        "target_to": 0,
        "actions": [
          {
            "type": "course|program|practice|mentoring|reading|shadowing|project",
            "title": "string",
            "description": "string"
          }
        ],
        "success_criteria": ["string"],
        "manager_support": ["string"]
      }
    ],
    "plan_summary": "string"
  }
}

Требования:
- не больше {{$json.development_plan_payload.constraints.max_competencies_per_quarter}} компетенций на квартал;
- использовать прежде всего переданные planning_candidates;
- предпочитать не более 6-8 компетенций на все полугодие;
- в каждом квартале должен быть баланс: не только обучение, но и практика;
- не придумывать learning assets, которых нет во входных данных;
