const learningAssetsByCompetency = new Map();
for (const asset of learningAssets) {
  if (asset.competencies && Array.isArray(asset.competencies)) {
    for (const comp of asset.competencies) {
      const normComp = normalize(comp);
      if (!learningAssetsByCompetency.has(normComp)) {
        learningAssetsByCompetency.set(normComp, []);
      }
      learningAssetsByCompetency.get(normComp).push({
        id: asset.id,
        title: asset.title,
        original_title: asset.original_title || asset.title,
        competencies: asset.competencies,
        _matched_competencies_count: asset._matched_competencies_count
      });
    }
  }
}

// Issue maps
const employeeIssuesMap = new Map();
for (const issue of employeeIssues) {
  const id = issue.entity_id;
  if (!employeeIssuesMap.has(id)) employeeIssuesMap.set(id, []);
  employeeIssuesMap.get(id).push(issue);
}

const selfAssessmentIssuesMap = new Map();
for (const issue of selfAssessmentIssues) {
  const id = issue.entity_id;
  if (!selfAssessmentIssuesMap.has(id)) selfAssessmentIssuesMap.set(id, []);
  selfAssessmentIssuesMap.get(id).push(issue);
}

// Process each employee into a result object
const employeeResults = [];

for (const emp of employees) {
  const employeeId = emp.employee_id;
  const employeeRole = emp.role;
  const issues = [];

  const selfAssessment = selfAssessmentMap.get(employeeId) || null;
  if (!selfAssessment) {
    issues.push({
      severity: 'error',
      entity_type: 'employee',
      issue_code: 'self_assessment_not_found',
      message: `Сотрудник ${employeeId} не имеет self-assessment`
    });
  }

  let roleMatrix = roleMatrixMap.get(employeeRole);
  if (!roleMatrix && roleMapping[employeeRole]) {
    roleMatrix = roleMatrixMap.get(roleMapping[employeeRole]);
  }
  if (!roleMatrix) {
    issues.push({
      severity: 'warning',
      entity_type: 'role_matrix',
      issue_code: 'role_matrix_not_found',
      message: `Не найдена матрица для роли ${employeeRole}`
    });
  }

  // Extract competencies from self-assessment and find matching learning assets
  const employeeCompetencies = new Set();
  if (selfAssessment && selfAssessment.assessments && selfAssessment.assessments.length) {
    const latest = selfAssessment.assessments[selfAssessment.assessments.length - 1];
    if (latest.items) {
      for (const item of latest.items) {
        const level = item.self_selected_level;
        if (typeof level === 'number' && level > 0) {
          const normComp = normalize(item.competency_id);
          employeeCompetencies.add(normComp);
        }
      }
    }
  }

  // Find matching learning assets for each assessment item
  const matchedLearningAssets = [];
  const uniqueAssetIds = new Set();

  if (selfAssessment && selfAssessment.assessments && selfAssessment.assessments.length) {
    const latest = selfAssessment.assessments[selfAssessment.assessments.length - 1];
    if (latest.items) {
      // Create a new array for items with added learning_assets
      const enrichedItems = [];

      for (const item of latest.items) {
        const level = item.self_selected_level;
        const isCompetence = typeof level === 'number' && level > 0;

        if (isCompetence) {
          const normComp = normalize(item.competency_id);
          const matchingAssets = learningAssetsByCompetency.get(normComp) || [];

          // Collect unique assets for the item
          const itemAssets = [];
          for (const asset of matchingAssets) {
            if (!uniqueAssetIds.has(asset.id)) {
              uniqueAssetIds.add(asset.id);
              matchedLearningAssets.push(asset);
            }
            itemAssets.push({
              id: asset.id,
              title: asset.title,
              original_title: asset.original_title
            });
          }

          // Add learning_assets to the item
          enrichedItems.push({
            ...item,
            learning_assets: itemAssets
          });
        } else {
          enrichedItems.push({
            ...item,
            learning_assets: []
          });
        }
      }

      // Update the assessment items with enriched data
      latest.items = enrichedItems;
    }
  }

  const empIssues = employeeIssuesMap.get(employeeId) || [];
  issues.push(...empIssues);
  const saIssues = selfAssessmentIssuesMap.get(employeeId) || [];
  issues.push(...saIssues);

  employeeResults.push({
    employee: emp,
    self_assessment: selfAssessment,
    role_matrix: roleMatrix,
    learning_assets_pool: matchedLearningAssets,
    employee_data_quality_issues: issues
  });
}

// Return final structure
return [{
  json: {
    employees: employeeResults,
    data_unstructured: mergedUnstructured
  }
}];

// Функция получения числового значения уровня
function getLevelValue(level) {
  if (level === undefined || level === null) return 0;
  if (typeof level === 'number') return level;
  if (typeof level === 'string') {
    const str = level.toLowerCase();
    if (str === 'not_applicable' || str === 'no_experience' || str === 'not_specified') return 0;
    const num = parseInt(str, 10);
    if (!isNaN(num)) return num;
  }
  return 0;
}

// Функция расчета приоритетного score для компетенции
function calculateScore(competencyData) {
  let score = 0;

  // 1. priority_weight из матрицы (базовый вес)
  score += competencyData.priorityWeight || 5;

  // 2. есть ли самооценка (не 0 и не no_experience и т.д.)
  if (competencyData.selfLevel && competencyData.selfLevel > 0) score += 10;

  // 3. есть ли комментарий от сотрудника
  if (competencyData.selfComment && competencyData.selfComment.trim() !== '') score += 15;

  // 4. есть ли Jira evidence
  if (competencyData.jiraEvidence && competencyData.jiraEvidence.length > 0) score += 20;

  // 5. есть ли gap до target level (чем больше gap, тем выше приоритет)
  const targetLevel = competencyData.targetLevel || 0;
  const currentLevel = competencyData.selfLevel || 0;
  const gap = targetLevel - currentLevel;
  if (gap > 0) score += gap * 15;

  // 6. soft skills чуть ниже приоритета (если есть критичные hard skills)
  if (competencyData.isSoftSkill) score -= 5;

  return score;
}

// Функция поиска target level из матрицы
function findTargetLevel(matrixCompetencies, competencyName) {
  const competency = matrixCompetencies.find(c => c.competency_name === competencyName);
  if (!competency || !competency.levels) return 0;

  // Берем максимальный уровень из матрицы как target
  let maxLevel = 0;
  for (const level of competency.levels) {
    const lvl = getLevelValue(level.level);
    if (lvl > maxLevel) maxLevel = lvl;
  }
  return maxLevel;
}

// Функция построения списка компетенций сотрудника
function buildCompetenciesList(employeeData) {
  const competenciesList = [];

  const roleMatrix = employeeData.role_matrix;
  const selfAssessment = employeeData.self_assessment;

  if (!roleMatrix || !roleMatrix.compentecy_groups) return competenciesList;

  // Создаем карту self-assessment для быстрого доступа
  const selfAssessmentMap = new Map();
  if (selfAssessment && selfAssessment.assessments && selfAssessment.assessments.length > 0) {
    const latestAssessment = selfAssessment.assessments[selfAssessment.assessments.length - 1];
    if (latestAssessment.items) {
      latestAssessment.items.forEach(item => {
        selfAssessmentMap.set(item.competency_id, {
          selfLevel: getLevelValue(item.self_selected_level),
          selfComment: item.self_comment || '',
          managerLevel: getLevelValue(item.manager_selected_level),
          managerComment: item.manager_comment || ''
        });
      });
    }
  }

  // Проходим по всем группам компетенций в матрице
  for (const group of roleMatrix.compentecy_groups) {
    if (!group.competencies) continue;

    for (const competency of group.competencies) {
      const competencyName = competency.competency_name;
      const selfData = selfAssessmentMap.get(competencyName) || {
        selfLevel: 0,
        selfComment: '',
        managerLevel: 0,
        managerComment: ''
      };

      const targetLevel = findTargetLevel(roleMatrix.compentecy_groups.flatMap(g => g.competencies), competencyName);

      // Определяем, является ли компетенция soft skill (можно расширить список)
      const softSkillsKeywords = ['менеджмент', 'коммуника', 'agile', 'обратная связь', 'наставничество', 'собеседовани', 'распространение знаний'];
      const isSoftSkill = softSkillsKeywords.some(keyword => competencyName.includes(keyword));

      const competencyData = {
        competencyName: competencyName,
        groupName: group.group_name,
        priorityWeight: 5, // базовый вес, можно настроить под категории
        selfLevel: selfData.selfLevel,
        selfComment: selfData.selfComment,
        managerLevel: selfData.managerLevel,
        managerComment: selfData.managerComment,
        targetLevel: targetLevel,
        isSoftSkill: isSoftSkill,
        jiraEvidence: [] // пока пустой массив, можно заполнить из внешнего источника
      };

      const score = calculateScore(competencyData);

      competenciesList.push({
        ...competencyData,
        score: score
      });
    }
  }

  // Сортируем по score (от большего к меньшему)
  competenciesList.sort((a, b) => b.score - a.score);

  return competenciesList;
}

// Получаем входные данные
const items = $input.all();
const inputData = items[0].json;
const employees = inputData.employees || [];

// Формируем результат
const employeesContextForPayload = [];

for (const employeeWrapper of employees) {
  const employee = employeeWrapper.employee;
  const selfAssessment = employeeWrapper.self_assessment;
  const roleMatrix = employeeWrapper.role_matrix;
  const learningAssetsPool = employeeWrapper.learning_assets_pool || [];
  const employeeIssues = employeeWrapper.employee_data_quality_issues || [];

  // Строим список компетенций с приоритетами
  const competenciesWithPriority = buildCompetenciesList({
    employee: employee,
    self_assessment: selfAssessment,
    role_matrix: roleMatrix
  });

  employeesContextForPayload.push({
    employee: employee,
    self_assessment: selfAssessment,
    role_matrix: roleMatrix,
    learning_assets_pool: learningAssetsPool,
    employee_data_quality_issues: employeeIssues,
    competencies_with_priority: competenciesWithPriority,
    competencies_count: competenciesWithPriority.length
  });
}

const result = {
  employees_context_for_payload: employeesContextForPayload
};

return [{ json: result }];

// n8n Code node
// Mode: Run Once for All Items

function asArray(v) {
  if (Array.isArray(v)) return v;
  if (v == null) return [];
  return [v];
}

function normalizeStr(v) {
  return String(v || "")
    .trim()
    .toLowerCase();
}

function slugify(v) {
  return normalizeStr(v)
    .replace(/[^\p{L}\p{N}]+/gu, "_")
    .replace(/^_+|_+$/g, "");
}

function firstNonEmpty(...values) {
  for (const v of values) {
    if (v !== undefined && v !== null && v !== "") return v;
  }
  return null;
}

function parseLevel(v) {
  if (v === null || v === undefined || v === "") return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function isSoftSkill(competency, groupName) {
  const text = normalizeStr(
    [
      competency?.competency_name,
      competency?.name,
      competency?.description,
      groupName,
    ].join(" ")
  );

  const softMarkers = [
    "soft",
    "коммуника",
    "заинтересован",
    "встреч",
    "фасилита",
    "презентац",
    "переговор",
    "обратн",
    "лидер",
    "ментор",
    "collaboration",
    "stakeholder",
  ];

  return softMarkers.some(m => text.includes(m));
}

function inferHardnessBoost(competency, groupName) {
  const text = normalizeStr(
    [
      competency?.competency_name,
      competency?.name,
      competency?.description,
      groupName,
    ].join(" ")
  );

  const hardMarkers = [
    "api", "sql", "архитект", "баз", "данн", "cicd", "jenkins",
    "mobile", "web", "backend", "frontend", "integration", "интеграц",
    "лог", "монитор", "безопас", "test design", "тест", "автоматиза",
    "framework", "фреймворк", "code", "ооп", "паттерн", "git"
  ];

  return hardMarkers.some(m => text.includes(m)) ? 1 : 0;
}

function calculateTargetLevel({ selfLevel, currentGrade, matrixMaxLevel = 4 }) {
  const gradeMap = {
    junior: 1,
    middle: 2,
    middle_high: 2,
    senior: 3,
    senior_high: 4,
    lead: 4,
    principal: 4,
  };

  const baseFromGrade = gradeMap[normalizeStr(currentGrade)] ?? 2;
  let target = baseFromGrade;

  if (selfLevel !== null) {
    target = Math.max(target, Math.min(selfLevel + 1, matrixMaxLevel));
  }

  return Math.min(target, matrixMaxLevel);
}

function calcPriorityScore({
  matrixPriorityWeight,
  hasSelfAssessment,
  hasComment,
  hasJiraEvidence,
  hasGap,
  isSoft,
  hardBoost,
}) {
  let score = 0;

  score += matrixPriorityWeight * 10;
  if (hasSelfAssessment) score += 20;
  if (hasComment) score += 10;
  if (hasJiraEvidence) score += 18;
  if (hasGap) score += 16;
  if (hardBoost) score += 8;
  if (isSoft) score -= 6;

  return Math.max(score, 0);
}

function scoreToPriority(score) {
  if (score >= 60) return "high";
  if (score >= 35) return "medium";
  return "low";
}

// Get the input data
const input = items[0].json;

// Get all employees from the context array
const employees = asArray(input.employees_context_for_payload || input);

// Array to store all results
const allResults = [];

// Process each employee
for (const employeeContext of employees) {
  // Extract data for this employee
  const matrices = asArray(employeeContext.role_matrix);
  const selfAssessmentRaw = employeeContext.self_assessment?.assessments?.[0]?.items || [];
  const jiraEvidenceRaw = asArray(employeeContext.jira_evidence || []);
  const employee = employeeContext.employee || {};
  const employeeGrade = firstNonEmpty(employee.grade);

  // Normalize self assessment into map
  const selfMap = new Map();

  for (const row of asArray(selfAssessmentRaw)) {
    const key = firstNonEmpty(
      row.competency_id,
      row.competencyId,
      slugify(row.competency_name || row.name)
    );

    if (!key) continue;

    // Handle both numeric and string level values
    let level = null;
    const rawLevel = firstNonEmpty(row.self_selected_level, row.self_level, row.level);
    if (rawLevel !== "not_applicable" && rawLevel !== "no_experience" && rawLevel !== "not_specified") {
      level = parseLevel(rawLevel);
    }

    selfMap.set(key, {
      competency_id: key,
      self_level: level,
      comment: firstNonEmpty(row.self_comment, row.comment, row.notes, row.text),
      raw: row,
    });
  }

  // Normalize jira evidence into map
  const evidenceMap = new Map();

  for (const row of asArray(jiraEvidenceRaw)) {
    const key = firstNonEmpty(
      row.competency_id,
      row.competencyId,
      slugify(row.competency_name || row.name)
    );

    if (!key) continue;

    const prev = evidenceMap.get(key) || [];
    prev.push({
      summary: firstNonEmpty(row.summary, row.title),
      key: firstNonEmpty(row.key, row.issueKey),
      status: firstNonEmpty(row.status),
      comment: firstNonEmpty(row.comment, row.description),
      raw: row,
    });
    evidenceMap.set(key, prev);
  }

  // Flatten matrix competencies
  const competencyItems = [];

  for (const matrix of asArray(matrices)) {
    const role = firstNonEmpty(matrix.role, employee.role);
    const groups = asArray(matrix.compentecy_groups || matrix.competency_groups);

    for (const group of groups) {
      const groupName = firstNonEmpty(group.group_name, group.name, "unknown_group");
      const competencies = asArray(group.competencies);

      for (const competency of competencies) {
        const competencyName = firstNonEmpty(
          competency.competency_name,
          competency.name,
          competency.title
        );

        if (!competencyName) continue;

        const competencyId = firstNonEmpty(
          competency.competency_id,
          competency.id,
          slugify(competencyName)
        );

        const levels = asArray(competency.levels);
        const matrixMaxLevel = levels.length
          ? Math.max(...levels.map(l => parseLevel(l.level)).filter(v => v !== null))
          : 4;

        const selfItem = selfMap.get(competencyId) || null;
        const jiraEvidence = evidenceMap.get(competencyId) || [];

        const selfLevel = selfItem?.self_level ?? null;
        const targetLevel = calculateTargetLevel({
          selfLevel,
          currentGrade: employeeGrade,
          matrixMaxLevel,
        });

        const gap = selfLevel !== null && targetLevel !== null
          ? Math.max(targetLevel - selfLevel, 0)
          : null;

        const soft = isSoftSkill(competency, groupName);
        const hardBoost = inferHardnessBoost(competency, groupName);

        const matrixPriorityWeight = Number(firstNonEmpty(
          competency.priority_weight,
          competency.priorityWeight,
          group.priority_weight,
          group.priorityWeight,
          hardBoost ? 3 : 2
        )) || 2;

        const priorityScore = calcPriorityScore({
          matrixPriorityWeight,
          hasSelfAssessment: !!selfItem,
          hasComment: !!selfItem?.comment,
          hasJiraEvidence: jiraEvidence.length > 0,
          hasGap: gap !== null && gap > 0,
          isSoft: soft,
          hardBoost,
        });

        competencyItems.push({
          employee_id: employee.employee_id,
          employee_login: employee.login,
          employee_name: employee.full_name,
          competency_id: competencyId,
          competency: {
            competency_id: competencyId,
            competency_name: competencyName,
            group_name: groupName,
            role,
            levels,
          },
          self_assessment_item: selfItem?.raw ?? null,
          jira_evidence: jiraEvidence,
          self_level: selfLevel,
          target_level: targetLevel,
          gap,
          matrix_priority_weight: matrixPriorityWeight,
          priority_score: priorityScore,
          priority: scoreToPriority(priorityScore),
          payload: {
            employee: {
              employee_id: employee.employee_id,
              login: employee.login,
              full_name: employee.full_name,
              grade: employeeGrade,
              role: firstNonEmpty(employee.role, role),
            },
            competency: {
              competency_id: competencyId,
              competency_name: competencyName,
              group_name: groupName,
              role,
              levels,
            },
            self_assessment: selfItem?.raw ?? null,
            jira_evidence: jiraEvidence,
            target_level: targetLevel,
            priority_score: priorityScore,
            priority: scoreToPriority(priorityScore),
          },
        });
      }
    }
  }

  // Sort and add to results
  competencyItems.sort((a, b) => b.priority_score - a.priority_score);
  allResults.push(...competencyItems);
}

// Return all results
return allResults.map(item => ({ json: item }));

// n8n Code node
// Mode: Run Once for All Items

const TOP_N = 5;

const sorted = [...items].sort(
(a, b) => (b.json.priority_score || 0) - (a.json.priority_score || 0)
);

return sorted.slice(0, TOP_N);

let result = $json;

if (typeof result === "string") {
result = JSON.parse(result);
}

if (typeof result.output === "string") {
result = JSON.parse(result.output);
}

if (typeof result.text === "string") {
result = JSON.parse(result.text);
}

return [
{
json: result,
},
];

const base =
  $('Code in JavaScript16').first().json.employees_context_for_payload?.[0] || {};

const competency_results = items
  .map(i => i.json.competency_result || i.json.normalized_result || i.json || null)
  .filter(Boolean);

return [{
  json: {
    employee: base.employee || {},
    self_assessment: base.self_assessment || null,
    role_matrix: base.role_matrix || null,
    learning_assets_pool: base.learning_assets_pool || [],
    employee_data_quality_issues: base.employee_data_quality_issues || [],
    jira_summary: base.jira_summary || {},
    config: base.config || {},
    competency_results
  }
}];

